var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……하아, 제길.","JPN":"……はあ、くそ。","ENG":"...*Sigh.* Bollocks.","TWN":"……哀，該死。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"로이?","JPN":"ロイ？","ENG":"Roy?","TWN":"羅伊？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"집에 안 들어가고 여기서 뭘 하고 있지?","JPN":"家に入らないで、何をしているんだ？","ENG":"What are you doing here? Aren't you supposed to be home?","TWN":"你怎麼不進門？站在外面幹什麼呢？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 할배였어?","JPN":"なんだ、ジジイか？","ENG":"Oh, Gramps, it's you.","TWN":"什麼啊，原來是爺爺啊？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"왔으면 진작 연락하지 그랬어?","JPN":"来てたのなら連絡しろよ。","ENG":"You could've told me if you were here.","TWN":"既然來了怎麼不早點聯繫我？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 또 빈손인 거야? 이번 낚시도 종쳤나 봐?","JPN":"で、また手ぶら？　今日の釣りもダメだったようだな。","ENG":"So, you're empty-handed again? Guess the fishing was a bust then, eh?","TWN":"所以又是兩手空空嗎？看來這次也沒釣成？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"쯧, 녀석 말버릇하고는……. 원래 낚시는 낚을 때까지 하는 거다.","JPN":"チッ、なんて口の利き方を……元々釣りは釣れるまでやるものだ。","ENG":"Tsk. You and your filthy mouth... You're supposed to fish until you catch something.","TWN":"嘖，你這傢伙說話的口氣可真……釣魚本來就是要釣到魚為止的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"오늘 못 잡았다고 실망할 것 없어. 내일은 잡을 수 있을 거라고 믿는 게 중요하니까.","JPN":"今日釣れなかったとして、がっかりする必要はない。明日は釣れると信じることが大切だからな。","ENG":"No need to be disappointed for not catching anything today. Believing that you can catch one the next day is what's important.","TWN":"不要因為今天沒抓到就感到失望，因為相信明天能抓到才是重要的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"맨날 말은 그렇게 하고서 한 마리도 못 잡는데 무슨.","JPN":"いつもそう言って一匹も釣れてないじゃないか。","ENG":"You always say that, but you never even caught one.","TWN":"每天都那麼說，卻一條都抓不到。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배가 자랑하던 특제 <color=#ffd34c>피시 앤 칩스</color>는 언제 맛볼 수 있는 건데?","JPN":"ジジイ自慢の特製<color=#ffd34c>フィッシュアンドチップス</color>には、いつありつけるんだ？","ENG":"When can I try your special <color=#ffd34c>fish and chips</color> you always talk about?","TWN":"到底什麼時候能嘗到爺爺一直引以為傲的特製<color=#ffd34c>炸魚薯條</color>啊？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"후후. 왜? 동네 하수도에서 배스라도 낚아다 줄까.","JPN":"ふふ。なんだ？　街の下水道でバスでも釣ってやろうか。","ENG":"Hah hah. Why, would you like me to catch a bass from a nearby sewers?","TWN":"呵呵，怎麼？要不在附近的下水道裡給你釣個鱸魚？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"으엑, 됐거든? 할배나 많이 해 드셔!","JPN":"げっ、いらねぇよ。一人で食べろよ！","ENG":"Ugh, forget it! You can keep it all to yourself!","TWN":"呃，算了吧！還是留給你自己吃吧！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 얼굴은 왜 그 모양이지? 혹시 누구한테 맞고 다니는 거냐?","JPN":"それで、その顔はどうした？　もしかして、誰かに殴られたのか？","ENG":"So, what's happened to your face? Are you being bullied?","TWN":"臉怎麼了？不會是被誰打了吧？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"딱히. 할배가 신경 쓸 일은 아니야.","JPN":"別に。ジジイが気にすることじゃない。","ENG":"Not really. It's none of your concern.","TWN":"不是，不用爺爺你操心。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"로버트 짓이냐?","JPN":"ロバートか？","ENG":"Was it Robert?","TWN":"是羅伯特幹的嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래! 그 망할 아버지한테 들이 받았다! 왜!","JPN":"そうだよ！　あのクソ親父とケンカした！　文句あるのか！？","ENG":"Yeah! I tackled him, so what?!","TWN":"沒錯！我頂撞了那個糟糕爸爸！怎樣！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 자식이 자꾸 술 먹고, 엄마를 때리려고 하잖아! 이제 됐어?","JPN":"あいつが酔っぱらって、お母さんを殴ろうとするからだ！　これで満足か？","ENG":"That bastard keeps drinking and trying to hit Mum! You happy?","TWN":"那傢伙老是喝酒，還想打媽媽呢！行了吧？！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 또 미안하다고 할 거면, 그냥 아무 말도 하지 마.","JPN":"ったく。またあの時みたいに、謝ったりするんじゃねぇぞ。","ENG":"Blimey. If you're going to apologize, keep it to yourself.","TWN":"真是，如果你又要和我說對不起，還是什麼都別說了吧。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어차피 할배 잘못 아닌 거 알고 있으니까.","JPN":"ジジイのせいじゃないってことくらい、わかってるし。","ENG":"I know it's not your fault anyway.","TWN":"反正我知道這不是你的錯。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 망할 집구석, 당신이 부쳐주는 돈 아니었으면 진작 다 쫄쫄 굶어 죽었어.","JPN":"こんなボロ家、あなたが送ってくれるお金がなかったら、とっくにみんな飢え死にしてたんだ。","ENG":"This bloody family would've starved to death if it weren't for the money you sent us.","TWN":"這個破地方，要不是爺爺你寄的錢，我們早就都餓死了。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 이제 와서 괜히 신경 써주는 척하지 말고, 친구들이랑 낚시나 실컷 다니라고.","JPN":"だから俺らのことは気にしないで、友達と釣りでも楽しんでてくれ。","ENG":"So, don't act like you care about us after everything. Just go fishing with your friends or something.","TWN":"所以你別現在才來裝出一副關心的樣子，還是跟大家釣魚去吧。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아버지를 때려 눕히든, 엄마를 떼어 놓든 내가 어떻게든 할 테니깐.","JPN":"親父を殴り飛ばすにしろ、お母さんから引き離すにしろ、俺がなんとかするから。","ENG":"I'll take care of it. Whether I knock down Dad or I separate Mum from him.","TWN":"不管是打倒我爸爸，還是帶媽媽離開這裡，我都自己會想辦法的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 네 말이 맞다.","JPN":"ああ、お前の言うとおりだ。","ENG":"You're right.","TWN":"沒錯，你說的對。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤 대의명분을 댄다 해도, 내가 너희 가족을 신경 쓰지 못한 건 사실이야.","JPN":"どんな大義名分も言い訳にならない。俺がお前の家族を見過ごしてきたのは事実だ。","ENG":"I can say it was for a noble cause, but it's still true that I wasn't able to take care of your family.","TWN":"不管雖然家人。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 와서…… 그 깊은 감정의 골을 해결하는 건 불가능하겠지.","JPN":"今更……その深い心の溝を埋めることは不可能だろう。","ENG":"And... it would be impossible to fill that deep of an emotional void now.","TWN":"事到如今……才來解決那早已破裂的感情是不可能的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대의명분? 갑자기 그게 무슨 헛소리야?","JPN":"大義名分？　なに言ってるんだ？","ENG":"\\"Noble cause\\"? Are you kidding me?","TWN":"資格？你突然說什麼亂七八糟的？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 로이.","JPN":"だが、ロイ。","ENG":"But Roy.","TWN":"但是，羅伊。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"겨우 그런 이유로 우리가, 버넷이 짊어진 업의 고리가 끊어져서는 안 돼.","JPN":"たかがそんな理由で俺たちが、バーネットが背負った業の輪が断たれてはいけない。","ENG":"That is not enough of a reason for us Burnetts to stop the cycle of duties we bear.","TWN":"不能僅僅因為那個原因，就讓伯內特家族背負的使命斷掉。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭔데, 이 쇠사슬은?","JPN":"なんだ、この鎖は？","ENG":"What is this chain?","TWN":"這個鐵鍊是什麼？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 이걸로 망할 아버지랑 한판 하라는 거야?","JPN":"これでクソ親父と一発やり合えってことか？","ENG":"You want me to fight my deadbeat dad with this?","TWN":"你是想讓我用這個東西和糟糕的爸爸打一架嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 헛소리를 하는 거냐?","JPN":"何を言っている。","ENG":"Stop the nonsense.","TWN":"你在胡說什麼？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"녀석이 사슬의 의미를 기억한다면, 다시는 널 때리지 않을 거다.","JPN":"やつがこの鎖の意味を覚えていたのなら、二度とお前を殴らないだろう。","ENG":"If he remembers what this chain means, he won't hit you ever again.","TWN":"他要是還記得鏈條的含義，就再也不會打你了。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"오히려 네 앞에서 벌벌 기게 되겠지.","JPN":"むしろお前の前で怯えることになるだろう。","ENG":"Rather, he'll likely cower and grovel in your presence.","TWN":"反而，會在你面前戰戰兢兢。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"왜냐하면 그건 몰락한 우리 가문의 상징 같은 거거든.","JPN":"何故ならこれは、没落した我が家門の象徴のようなものだからな。","ENG":"Because that's something of a symbol of our fallen house.","TWN":"因為這是我們沒落的家族象徵。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"가문의 상징이라고?","JPN":"家門の象徴？","ENG":"A symbol of our house?","TWN":"家族象徵？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"할아버지의 말은 사실이었다.","JPN":"お爺さんの話は本当だった。","ENG":"What he said was true.","TWN":"爺爺的話是真的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그 날 이후, 아버지는 나와 어머니에게 한 번도 주먹을 휘두른 적이 없다.","JPN":"あの日以来、親父は俺とお母さんに一度も暴力を振ったことがない。","ENG":"From that day on, Dad never laid a hand on me or Mum again.","TWN":"從那天以後，爸爸就再也沒有對我和媽媽動過拳頭。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 그로부터 얼마 지나지 않아.","JPN":"そして、それから間もなく。","ENG":"And not too long after that.","TWN":"然而沒過多久……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"할아버지의 부고 소식이 들려왔다.","JPN":"お爺さんの訃報が届いた。","ENG":"I heard about my grandfather's passing.","TWN":"就傳來了爺爺的死訊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네가 봉인 사슬을 가지고 있을 때부터 예상하긴 했지만.","JPN":"君が封印の鎖を持っていたときから予想はしていたのだが。","ENG":"I assumed so when I saw you with the Sealing Chain,","TWN":"我看到你拿著封印鎖鏈的時候就已經預料到了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아마 그때부터 형님은 자네에게 프리드웬을 맡길 생각을 하고 계셨던 것 같아.","JPN":"恐らく、その時からバーネットは君にプリドウェンを任せようと考えていたようだな。","ENG":"but it seems like your grandfather had planned to hand over Prydwen to you since then.","TWN":"也許從那時起，大哥就有了把普利多溫託付給你的想法。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"방패를 다루기 위해서는 그 부산물인 사슬부터 익숙해져야 하거든.","JPN":"盾を扱うためには、その副産物である鎖の扱いから覚える必要がある。","ENG":"In order to handle the shield, you first need to get used to the chain, which is the by-product of it.","TWN":"為了操控盾牌，首先就要熟悉那個作為附屬品的鐵鍊。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 가문의 상징이라는 게 그런 뜻이었다니.","JPN":"チッ、家門の象徴がそんな意味を持ってたなんて。","ENG":"Tsk. So that's what he meant by \\"symbol of our house.\\"","TWN":"嘖，家族的象徵竟然是這個意思。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 망할 아버지는 뭐야?","JPN":"で、クソ親父はなんだ？","ENG":"So what's with my deadbeat dad?","TWN":"所以，關於我那個糟糕的爸爸又是什麼？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 짓을 저질렀길래, 홍차 폭탄이 책임을 져버리고 도망쳤다고 말하는 거야?","JPN":"紅茶爆弾の言う、責任に背いて逃げたってなんのことだよ。","ENG":"What did he do that made Tea Bomb say that he abandoned his responsibilities and ran away?","TWN":"究竟犯了什麼罪，紅茶炸彈才會說他拋棄責任逃跑了？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"으음, 로버트가 그렇게 된 건…….","JPN":"うむ、ロバートがああなったのは……","ENG":"Mm, perhaps what happened with Robert was...","TWN":"嗯，羅伯特之所以會變成那樣……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어쩌면 기관 내에서 형님의 위상이 너무 커서 그랬던 것일지도 모르지.","JPN":"もしかしたら、機関内でバーネットの地位が高すぎたせいかもな。","ENG":"a result of the high status your grandfather holds within the Institution.","TWN":"或許是因為大哥在機關裡的地位太高了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 아가씨의 아버지. 그러니까 전대 기관장 시절이었어.","JPN":"そうだ、お嬢様のお父さん。つまり、先代機関長の時代だった。","ENG":"See, it was the previous chief's, Lady Elizabeth's father's, time.","TWN":"是的，小姐的父親，也就是上一任機關長時期。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"돌이켜보면 기관이 가장 강했던 시절이었지. 은퇴를 앞두셨지만 버넷 형님도 현역이셨고.","JPN":"思い返せば、機関がもっとも強かった時代だ。引退目前ではあったが、バーネットも現役だった。","ENG":"When I think back on it, it was when the Institution held the most power. Sir Burnett was still working, even though he was close to retirement.","TWN":"回想起來，那時是機關最強大的時候。雖然馬上就要退休了，但伯內特大哥依舊在職。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 형님께는 아들이 하나 있었지.","JPN":"そして、バーネットには息子が一人いた。","ENG":"And he had a son.","TWN":"而且大哥還有一個兒子。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 전설적인 버넷 형님의 아들이니까 기관의 차기 유망주라고 다들 난리도 아니었어.","JPN":"あの伝説的なバーネットの息子だったから、機関の次期エースだとみんな噂していたんだ。","ENG":"As the son of the legendary Burnett, everyone treated him like the Institution's next up-and-comer.","TWN":"畢竟是傳奇伯內特大哥的兒子，所以大家都說他是機關的下一個希望之星。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"로버트 본인도 자신의 위치를 잘 알고 있었지. 어쩌면 자부심까지 갖고 있었을지도 몰라.","JPN":"ロバートも自分の位置をよくわかっていた。もしかしたら、それに対するプライドもあったのかもしれない。","ENG":"Robert was well aware of his position. He might have had pride in it, too.","TWN":"羅伯特本人也非常清楚自己的位置，說不定還挺有驕傲的。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 동시에 과격한 면이 있었던 것도 사실이야.","JPN":"だが彼には同時に、過激な一面もあった。","ENG":"However, he also had an extreme side.","TWN":"但同時也有偏激的一面，這也是事實。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬을 계승하자마자, 로버트는 한 방에 학회를 근절시키려는 계획을 구상했으니까.","JPN":"プリドウェンを継承した直後、ロバートは一発で学会を根絶やしにする計画を構想していたからな。","ENG":"As soon as Robert inherited Prydwen, he came up with a plan to eradicate the Society in one go.","TWN":"繼承了普利多溫後，羅伯特立即構想了根除學會的計畫。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"학회를 근절시킨다고? 어떻게?","JPN":"学会を根絶やしに？　どうやって？","ENG":"Eradicate the Society? How?","TWN":"根除學會？怎麼做？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"맥크레디와의 협력을 통해서.","JPN":"マクレディーとの協力を通じて、だ。","ENG":"Through cooperating with MacCready.","TWN":"透過與麥克蕾蒂的合作。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"학회의 정기 회동 일시와 장소를 알아낸 뒤, 학회장과 학부장을 전부 제거할 계획이었어.","JPN":"学会の定期会合の日付と場所を探し、学会長と学部長を一斉除去する計画だった。","ENG":"Our plan was to figure out the time and location of the Society's regular meetings and eliminate the President and all the deans.","TWN":"打聽到學會的定期會議時間和地點後，準備把學會會長和學院院長全部清除。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 무슨 소리를 하는 거야? 맥크레디라고?","JPN":"待てよ、なんの話だ？　マクレディー？","ENG":"Wait, did you just say MacCready?","TWN":"等等，你在說什麼？麥克蕾蒂？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 현 학회장인 레지나 맥크레디의 아버지라네.","JPN":"ああ、現学会長のレジーナ・マクレディーのお父さんだ。","ENG":"Yes. The father of the current President, Regina MacCready.","TWN":"沒錯，就是現任學會會長蕾佳娜·麥克蕾蒂的父親。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"지식의 호수에 미쳐있던 맥크레디 가문이 대를 잇기 위해 들인 데릴사위…….","JPN":"知識の湖にこだわっていたマクレディー家が、家を継ぐために迎え入れた婿養子……","ENG":"The MacCready family was obsessed with the Lake of Knowledge, and they brought him into the MacCready family to carry on the family name.","TWN":"沉迷于知識湖水的麥克蕾蒂家族，為了傳宗接代而入贅女婿……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그는 처음부터 기관이 준비해둔 인물이었어.","JPN":"だが、彼は最初から機関が準備した人物だった。","ENG":"But he was someone arranged by the Institution from the start.","TWN":"但他從一開始就是機關安排的人物。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"다시 말해, 절대 들켜서는 안 되는…… 우리 측의 가장 중요한 핵심 정보원이었다네.","JPN":"つまり、決してバレてはいけない……こちらのもっとも重要な核心情報員だったのだよ。","ENG":"In other words... he was our most important intel agent that should never have been caught.","TWN":"就是說，是千萬不能被發現的……我們最重要的核心情報員。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だって……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"말도 안 돼. 그런 위험한 짓을 했단 말이야?","JPN":"バカな。そんな危ないことをしてたのか？","ENG":"No way. He actually did something that risky?","TWN":"怎麼可能。怎麼會做出那麼危險的事？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"생각해보게. 그 시절은, 관리 실패가 발생하고 얼마 지나지 않았을 때였어.","JPN":"考えてみろ。あの頃は、管理の失敗が発生して間もない時期だった。","ENG":"Think about it. It was not long after the Administration Failure.","TWN":"你想想，那是管理失敗後沒過多久的時候。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"평화를 위해서라면, 다들 어떤 희생도 감수할 수 있다는 분위기가 흐르던 시절이었지.","JPN":"平和のためになら、どんな犠牲も厭わないという雰囲気が蔓延していた時代だったんだ。","ENG":"It was a time when the masses would risk anything for peace.","TWN":"當時，人們普遍認為，只要是為了和平，大家可以做出任何犧牲。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정보원으로부터 맥크레디 포인트의 봉쇄 좌표를 획득한 로버트는 기습 작전을 수행했네.","JPN":"情報員からマクレディーポイントの封鎖座標を獲得したロバートは、奇襲作戦を行った。","ENG":"Robert received the sealing coordinates for MacCready Point from the intel agent and conducted an ambush operation.","TWN":"羅伯特從情報員那裡得到了麥克蕾蒂領地的封鎖座標後，進行了偷襲。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그는 첫 작전임에도 불구하고, 승리를 낙관하고 있었어.","JPN":"だが、彼は初めての作戦であったにも関わらず、勝利を楽観視していた。","ENG":"However, he was too sure of his victory despite it being his first operation.","TWN":"盡管是第一次行動，但他還是對勝利持樂觀態度。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우리가 적으로부터 정보를 빼 왔듯, 우리 정보도 적에게 새어 나가고 있었거든.","JPN":"俺たちが敵から情報を抜いていたように、俺たちの情報も敵に漏れていたのだ。","ENG":"Similar to how we got intel on the enemy, our information was being leaked to the enemy as well.","TWN":"但就像我們從敵人那裡竊取到了情報一樣，我們作戰的情報也被洩露到了敵人那裡。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"결국, 기습 작전은 실패로 돌아갔고 작전에 투입된 요원들은 일방적으로 학살당했지.","JPN":"結局、奇襲作戦は失敗し作戦に投入されたエージェントたちは一方的に虐殺された。","ENG":"Eventually, the ambush operation failed and the agents that were assigned to the operation were all murdered.","TWN":"最終，偷襲作戰失敗，投入作戰的人員被單方面屠殺。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 측 핵심 정보원도 그때 숙청당한 걸로 추정된다네.","JPN":"こちらの核心情報員も、あの時に粛清されたと推定される。","ENG":"It is assumed that our prime intel agent was purged during the process as well.","TWN":"據推測，我方核心情報員也在當時被除掉。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 영향력이 약해진 건, 그 날의 여파가 여전히 남아있기 때문이야.","JPN":"機関の影響力が弱くなったのは、あの日の余波が未だに残っているからだよ。","ENG":"The Institution's influence is weaker because of the aftermath of that day.","TWN":"機關的影響力之所以減弱，就是因為當天的餘波仍然存在。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고…… 나도 그날의 작전에서 한쪽 눈을 잃고 말았어.","JPN":"そして……俺もあの日の作戦で片目を失った。","ENG":"And... I lost my one eye from that operation too.","TWN":"還有……我也在當天的作戰中失去了一隻眼睛。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 작전 정보가 샜던 경로가…….","JPN":"機関の作戦情報が漏れたルートって……","ENG":"Are you saying that the Institution's leak...","TWN":"機關作戰消息洩露的途徑……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"설마, 우리 아버지였다는 거야?","JPN":"まさか、親父……？","ENG":"was my father?","TWN":"難道，是我的父親嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 작전은 기밀 중의 기밀이었다네. 나조차 작전 당일 브리핑을 받았으니까.","JPN":"あの作戦は機密中の機密だったのだよ。俺も当日に詳細を聞いたからな。","ENG":"That operation was top secret. Even I was briefed on the day of the operation.","TWN":"作戰是機密中的機密，連我也是在當天才收到了作戰報告。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"본인은 자기가 아니라고 부정했지만, 어차피 그 작전의 총책임자는 로버트였어.","JPN":"本人は自分ではないと否定したが、どのみち作戦の総責任者はロバートだった。","ENG":"He denied it, but Robert was in charge of that operation.","TWN":"他否認不是自己做的，但不管怎麼說，作戰的總負責人是羅伯特。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"징계가 결정된 날, 그는 홧김에 물려받은 프리드웬을 내동댕이치고 기관을 떠났지.","JPN":"懲戒が決まった日、彼は怒って受け継いだプリドウェンを投げ捨て機関を出た。","ENG":"The day his punishment was determined, he threw his inherited Prydwen on the ground in a fit of anger and left the Institution.","TWN":"決定對他實行處罰的那天，他一氣之下便扔下繼承的普利多溫離開了機關。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 날을 떠올리면…… 나는 여전히 치가 떨리네.","JPN":"あの日のことを思い出すと……俺はまだ身震いしてしまう。","ENG":"I can't help but get furious... when I think of that day.","TWN":"想起那一天……我仍然氣得牙癢癢的。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그자에게 버넷이라는 이름만 없었다면, 내 손으로 박살내 버렸을 거야.","JPN":"あいつの苗字がバーネットでなければ、この手で殴り倒していただろう。","ENG":"If his last name wasn't Burnett, I would've ended him with my own two hands.","TWN":"要不是他有著伯內特的姓氏，我早就親手把他打死了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"결국, 이를 만회하기 위해 버넷 형님께선 은퇴까지 미루고 현장을 뛰게 되셨지.","JPN":"結局、名誉を挽回するためにバーネットは引退を引き延ばしてまで現場で働くハメになった。","ENG":"So, your grandfather had to postpone his retirement and work out on the field to make up for this.","TWN":"最後，為了彌補這一損失，伯內特大哥延後退休，一直奔波在現場。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 사정을 알게 되니 속이 좀 후련하나?","JPN":"どうだ、事情がわかって、すっきりしたか？","ENG":"Do you feel relieved knowing what happened?","TWN":"現在你已經了解情況了，心裡好受些了嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"전혀. 훨씬 찝찝해졌어.","JPN":"全然。余計にモヤモヤするよ。","ENG":"Not at all. I'm a lot more disturbed.","TWN":"不，反而更不舒服了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하하, 원래 진실이란 게 다 그런 거 아니겠나?","JPN":"ははは、真実なんて、そんなもんさ。","ENG":"Hah hah hah. That's what the truth will do to you.","TWN":"哈哈哈，真相本來不就是這樣嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……그래도.","JPN":"……でも。","ENG":"...Still.","TWN":"……就算如此。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"역시 아무것도 모르고 있었던 것보단 훨씬 나아. ","JPN":"やっぱり何も知らないよりはずっとましだ。 ","ENG":"It's better than not knowing anything.","TWN":"但還是比什麼都不知道要好得多。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"사실대로 말해줘서 고마워, 모건 할배.","JPN":"本当のことを話してくれてありがとう、モーガンのジジイ。","ENG":"Thanks for telling me the truth, Morgan.","TWN":"謝謝你如實告訴我，摩根老頭。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우리의 숙업이 다할 때까지, 기관은 계속해서 버넷의 힘을 필요로 할 거라네.","JPN":"俺たちが使命を果たすまで、機関は引き続きバーネットの力を必要とするだろう。","ENG":"The Institution will continue to need the power of the Burnetts until our goal is achieved.","TWN":"在我們完成霸業之前，機關仍需要伯內特的力量。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 이름이 자네의 전부가 되어서는 안 돼.","JPN":"だが、その名に慢心してはいけない。","ENG":"But your name mustn't define your whole existence.","TWN":"但是別讓名字決定你這個人。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"신사의 품격은 행동에서 비롯되는 법이니까 말이지.","JPN":"紳士の品格は、行動から始まるものだからな。","ENG":"A gentleman is defined by his actions, after all.","TWN":"因為禮儀成就非凡。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"모건 요원님. 말씀 중에 죄송합니다만.","JPN":"モーガン様。お話し中、申し訳ありませんが……","ENG":"Agent Morgan. Sorry to disturb you.","TWN":"摩根特工，很抱歉打斷你的話。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L36_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"아무래도 점점 눈보라가 심해져서, 여기부터는 직접 내려서 가셔야 할 것 같습니다.","JPN":"ひどい吹雪のため、ここで降りて歩いて向かうしかなさそうです。","ENG":"The snowstorm is getting worse, so it looks like you'll have to get to the destination yourselves.","TWN":"暴風雪越來越嚴重了，從這裡開始得親自下車走。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"근처 착륙지점에 내려드리겠습니다.","JPN":"近くの着陸地点に着陸します。","ENG":"I'll land on a nearby landing site.","TWN":"我會在附近的著陸點停車。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋네. 안 그래도 슬슬 입에서 단내가 날 지경이었거든.","JPN":"いいだろう。ちょうど口が疲れてくるころだったのだよ。","ENG":"Very well. It was starting to get a bit tedious anyway.","TWN":"好吧，正好我也說累了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"방호복 챙기게. 침식파 섞인 눈을 맞으면 머리카락 벗겨지는 걸로는 안 끝날 테니까.","JPN":"防護服を用意しろ。侵食波が混ざった雪に降られると、ハゲるだけでは済まないぞ。","ENG":"Get your protective suit. You'll lose more than just your hair if you are exposed to snow mixed with Corruption ray.","TWN":"帶上防護服。如果被混雜著侵蝕波的雪沾到，就不僅僅是掉頭發這麼簡單了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 기적심의회 제9본부","JPN":"<color=#ffd34c>聖皇庁</color>奇跡審議会第9本部","ENG":"<color=#ffd34c>Holy Curia</color> Miracle Investigation Council 9's HQ","TWN":"<color=#ffd34c>聖皇廳</color> 第九奇蹟議會"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그렇지. 자네 혹시 현찰 가진 거 있나?","JPN":"ああ、そうだ。君、現金は持っているか？","ENG":"Ah, right. Do you carry any cash with you?","TWN":"啊，對了。你有現金嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야? 왜 갑자기 돈을 뜯고 난리야? 요즘 현금 가지고 다니는 사람이 어디 있다고.","JPN":"なんだよ、カツアゲか？　このご時世、現金を持ち歩くやつなんていないだろ。","ENG":"Huh? Are you trying to rob me or something? No one carries around cash these days.","TWN":"幹嘛？為什麼突然找我要錢？最近哪有人帶現金啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이거 난처하게 됐군. 성당에 오면서 헌금을 챙기는 걸 깜빡하다니.","JPN":"これは参ったな。聖堂に来て、献金を忘れるとは。","ENG":"This is embarrassing. I forgot to bring offerings to the church.","TWN":"這就為難了。來教堂，竟然忘了拿捐款。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 그런 게 뭐가 중요해? 우리가 무슨 고해성사를 하러 온 것도 아니고.","JPN":"ったく。そんなもんどうでもいいだろ？　神父様に会いに来たわけでもないんだし。","ENG":"Blimey. That's not what's important. We're not here to make a confession.","TWN":"真是的，那有什麼重要的？我們又不是來懺悔的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"쯧쯧. 이래서 자네가 아직 애송이라는 거야.","JPN":"チッチッ。これだから君はまだ小僧なのだよ。","ENG":"Tsk, tsk. That's why you're still just a kid.","TWN":"嘖嘖，所以說你還是個小鬼。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"요원이라면 꼭 알아두게. 원래 공적인 자리일수록, 체면치레라는 게 중요한 거야.","JPN":"エージェントなら肝に銘じておけ。公的な場であるほど、見栄というものが大事になるんだ。","ENG":"You're an agent, so you should know. These kinds of occasions call for formalities.","TWN":"身為特工一定要明白，越是公開場合，面子就越重要。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"마음에 없어도, 일단 호감을 사두는 편이 뭘 부탁하기도…….","JPN":"その気はなくても、とりあえず好感を与えた方がいい。何かを頼む時にも……","ENG":"Even if you don't mean it, it's useful to make a good impression for later on–","TWN":"即使心裡不樂意，但還是先建立好關係，那以後拜託什麼……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"제 기억에 따르면 다음에 방문하실 땐, 고해성사를 하실 거라고 했던 것 같습니다만.","JPN":"私の記憶では、次訪問された際には神に赦しを請いたいとおっしゃっていましたよね。","ENG":"According to my memory, you had mentioned how you would make a confession the next time you were to visit.","TWN":"我記得你說過，下次拜訪的時候會來懺悔。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네는?","JPN":"君は？","ENG":"You are?","TWN":"你是？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그것도 체면치레로 하신 말씀이셨군요.","JPN":"あれも見栄だったとは。","ENG":"It seems like that was merely part of the formalities.","TWN":"原來那也是客套話。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"참고로 요즘은 계좌이체로도 헌금이 가능하답니다, 새디어스 모건.","JPN":"ちなみに、最近の献金は振り込みでも受け付けていますよ。タデウス・モーガン。","ENG":"For your information, you can give offerings via wire transfers nowadays. Thaddeus Morgan.","TWN":"作為參考，最近還可以轉帳捐款，薩迪烏斯·摩根先生。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하, 하하. 그런가? 이거 참 세상 많이 좋아졌군.","JPN":"は、はは。そうか？　これは、いい時代になったものだな。","ENG":"H-hah hah. Is that so? I guess they've made great strides in technology.","TWN":"哈，哈哈。是嗎？這世界真是方便了許多。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};